INSERT INTO download_task (
    message_id, chat_id, status
    , chat_title
    , file_name
    , file_size
    , mime_type
    , local_path
    , error_message
    , remote_url
    , upload_status
    , telegram_file_id
    , telegram_unique_file_id
    , downloaded_size
    , message_data
    , chat_config_id
    , extra_data
    , is_stop_transmission
    , started_at
    , finished_at
    , total_task
    , success_task
    , failed_task
    , skip_task
    , download_speed
    , bot_chat_id
    , bot_message_id
) VALUES (
    #{messageId}, #{chatId}, #{status}
    , #{chatTitle}
    , #{fileName}
    , #{fileSize}
    , #{mimeType}
    , #{localPath}
    , #{errorMessage}
    , #{remoteUrl}
    , #{uploadStatus}
    , #{telegramFileId}
    , #{telegramUniqueFileId}
    , #{downloadedSize}
    , #{messageData}
    , #{chatConfigId}
    , #{extraData}
    , #{isStopTransmission}
    , #{startedAt}
    , #{finishedAt}
    , #{totalTask}
    , #{successTask}
    , #{failedTask}
    , #{skipTask}
    , #{downloadSpeed}
    , #{botChatId}
    , #{botMessageId}
)
